/**
 * @description Macro E2E용 최소 원시 파일 바이트(PDF/DOCX/PPTX). AI 파싱·S3 bundle 복사 검증에 사용합니다.
 */

/** %PDF-1.1 최소 헤더 */
export const MINIMAL_PDF_BYTES = Buffer.from(
  '%PDF-1.1\n1 0 obj<<>>endobj\ntrailer<<>>\n%%EOF\n'
);

/** Office Open XML 최소 DOCX (zip) */
export const MINIMAL_DOCX_BYTES = Buffer.from(
  '',
  'base64'
);

/** 알 수 없는 확장자 E2E용 최소 바이트 */
export const MINIMAL_UNKNOWN_BYTES = Buffer.from('E2E unknown extension stub\n', 'utf-8');

/** Office Open XML 최소 PPTX (zip) */
export const MINIMAL_PPTX_BYTES = Buffer.from(
  '',
  'base64'
);
